# Minimal chess legality checker for verifying our positions.
# Board: dict square->piece. Square = (file 0-7 a-h, rank 0-7 = ranks 1-8)

def sq(f,r): return (f,r)
def inb(f,r): return 0<=f<8 and 0<=r<8

def king_moves(f,r):
    for df in (-1,0,1):
        for dr in (-1,0,1):
            if df==0 and dr==0: continue
            if inb(f+df,r+dr): yield (f+df,r+dr)

def knight_moves(f,r):
    for df,dr in [(1,2),(2,1),(-1,2),(-2,1),(1,-2),(2,-1),(-1,-2),(-2,-1)]:
        if inb(f+df,r+dr): yield (f+df,r+dr)

def rook_rays(f,r,occ):
    res=[]
    for df,dr in [(1,0),(-1,0),(0,1),(0,-1)]:
        nf,nr=f+df,r+dr
        while inb(nf,nr):
            res.append((nf,nr))
            if (nf,nr) in occ: break
            nf+=df; nr+=dr
    return res

def queen_rays(f,r,occ):
    res=rook_rays(f,r,occ)
    for df,dr in [(1,1),(1,-1),(-1,1),(-1,-1)]:
        nf,nr=f+df,r+dr
        while inb(nf,nr):
            res.append((nf,nr))
            if (nf,nr) in occ: break
            nf+=df; nr+=dr
    return res

def bishop_rays(f,r,occ):
    res=[]
    for df,dr in [(1,1),(1,-1),(-1,1),(-1,-1)]:
        nf,nr=f+df,r+dr
        while inb(nf,nr):
            res.append((nf,nr))
            if (nf,nr) in occ: break
            nf+=df; nr+=dr
    return res

def attacks(board, by_white):
    # squares attacked by side
    occ=set(board.keys())
    att=set()
    for (f,r),p in board.items():
        is_white=p.isupper()
        if is_white!=by_white: continue
        pl=p.lower()
        if pl=='k':
            att|=set(king_moves(f,r))
        elif pl=='n':
            att|=set(knight_moves(f,r))
        elif pl=='r':
            att|=set(rook_rays(f,r,occ))
        elif pl=='q':
            att|=set(queen_rays(f,r,occ))
        elif pl=='b':
            att|=set(bishop_rays(f,r,occ))
        elif pl=='p':
            dr=1 if is_white else -1
            for df in (-1,1):
                if inb(f+df,r+dr): att.add((f+df,r+dr))
    return att

def find_king(board, white):
    for (f,r),p in board.items():
        if p==('K' if white else 'k'): return (f,r)
    return None

def legal_king_moves(board, white):
    # moves of the side-to-move king that don't land on attacked square
    k=find_king(board,white)
    occ=board
    res=[]
    for (nf,nr) in king_moves(*k):
        # can't move onto own piece
        tp=board.get((nf,nr))
        if tp and (tp.isupper()==white): continue
        # simulate
        nb=dict(board)
        del nb[k]
        nb[(nf,nr)]=('K' if white else 'k')
        if (nf,nr) not in attacks(nb, not white):
            res.append((nf,nr))
    return res

def in_check(board, white):
    k=find_king(board,white)
    return k in attacks(board, not white)

def sqname(f,r): return "abcdefgh"[f]+str(r+1)

